// Build the actual Kafka producer payload and side-emit per-file metrics.
const envelope = msg.envelope;
const filename = msg.filename;
const routingTopic = msg.routing_topic;

// Kafka producer node consumes msg.topic, msg.key, msg.payload
const kafkaMsg = {
    topic: routingTopic,
    key: filename,
    payload: JSON.stringify(envelope)
};

// Stash original envelope so DLQ can include it on publish failure.
kafkaMsg._sftp_envelope = envelope;
kafkaMsg._sftp_filename = filename;

// Increment records counter immediately (matches Python flow which counts
// before flush). On delivery failure the catch handler increments DLQ
// counter separately; we accept a tiny over-count window for simplicity.
const m = global.get('metrics') || {};
m.facis_sftp_records_published_total = (m.facis_sftp_records_published_total || 0) + 1;

// File-level dedup: count files-ingested only once per (tick, filename)
// pair. Without this we'd count every record's filename.
const seenKey = 'files_seen_' + (msg.tick_id || 'no-tick');
let seen = flow.get(seenKey) || new Set();
if (!(seen instanceof Set)) seen = new Set(seen);
let fileMetric = null;
if (!seen.has(filename)) {
    seen.add(filename);
    flow.set(seenKey, seen);
    const ext = filename.includes('.') ? filename.slice(filename.lastIndexOf('.') + 1) : 'unknown';
    m.facis_sftp_files_ingested_total = m.facis_sftp_files_ingested_total || {};
    m.facis_sftp_files_ingested_total[ext] = (m.facis_sftp_files_ingested_total[ext] || 0) + 1;
}
global.set('metrics', m);

return kafkaMsg;

const original = msg && msg._sftp_envelope ? msg._sftp_envelope : null;
const filename = msg && msg._sftp_filename ? msg._sftp_filename : null;
const dlq = {
    error_type: 'publish',
    error_message: msg.error ? (msg.error.message || String(msg.error)) : 'unknown publish error',
    error_timestamp: new Date().toISOString(),
    filename: filename,
    source_topic: original ? original.source_topic : null,
    original_envelope: original
};
return { payload: dlq, filename: filename };
